SELECT * FROM (
  SELECT * FROM szzw.t_yqyc_wf_ticket
  WHERE business_id = #{businessId}

      AND ticket_type = #{ticketType}

  ORDER BY id DESC
)  WHERE ROWNUM = 1

SELECT * FROM szzw.t_yqyc_wf_ticket
WHERE ticket_type = #{ticketType}
  AND group_id IN

    #{gid}

  AND ticket_status IN ('待审核','驳回')
ORDER BY submit_time DESC
